from flask import Flask, request, jsonify
from pymemcache.client.base import Client
import pymysql

app = Flask(__name__)
memcached_client = Client(('localhost', 11211))

def get_db_connection():
    return pymysql.connect(host='localhost', user='yourusername', password='yourpassword', db='yourdb')

@app.route('/api/query', methods=['GET'])
def query_data():
    cache_key = 'query_data'
    cached_data = memcached_client.get(cache_key)

    if cached_data:
        return jsonify(cached_data)

    db_conn = get_db_connection()
    cursor = db_conn.cursor()
    cursor.execute("SELECT * FROM yourtable")
    data = [row for row in cursor]
    db_conn.close()

    memcached_client.set(cache_key, data, expire=60*30) # cache for 30 minutes (in seconds)
    return jsonify(data)

if __name__ == '__main__':
    app.run(debug=True)